def nums(nums: Array[Long]): Array[Long] = {
  val n = nums.length
  // Create the resulting array of size 2*n
  val ans = new Array[Long](2 * n)

  // Copy the first n elements: ans[i] = nums[i] for 0 <= i < n
  for (i <- 0 until n) {
    ans(i) = nums(i)
  }

  // Copy the reversed elements: ans[i + n] = nums[n - i - 1] for 0 <= i < n
  for (i <- 0 until n) {
    // The index in nums for the reversed part is n - 1 - i
    val numsIndex = n - 1 - i
    // The index in ans is n + i
    ans(n + i) = nums(numsIndex)
  }

  ans
}
